interface UserContext {
  playerId: string;
  userName: string;
}

function isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseUserContext(req: express.Request): UserContext {
  const body = isObject(req.body) ? req.body : {};
  const userId = body.userId ?? req.header("x-user-id") ?? req.query.userId;
  const userName = body.userName ?? req.header("x-user-name") ?? req.query.userName ?? "Player";

  if (typeof userId !== "string" || userId.trim().length === 0) {
    throw new Error("userId is required");
  }

  if (typeof userName !== "string" || userName.trim().length === 0) {
    throw new Error("userName is required");
  }

  return {
    playerId: userId,
    userName,
  };
}

function emitTutorialEvent(roomManager: RoomManager, io: SocketIOServer, roomId: string, event: EngineEvent): void {
  const room = roomManager.getRoomById(roomId);
  if (!room || room.roomType !== "tutorial") {
    return;
  }

  const user = room.players.find((player) => !player.isBot);
  if (!user?.socketId) {
    return;
  }

  if (event.type === "tutorial_step_changed") {
    io.to(user.socketId).emit("tutorial:stepChanged", event.payload);
    return;
  }

  if (event.type === "tutorial_hint") {
    io.to(user.socketId).emit("tutorial:hint", event.payload);
    return;
  }

  if (event.type === "tutorial_completed") {
    io.to(user.socketId).emit("tutorial:completed", event.payload);
  }
}

function sanitizeError(error: unknown): { message: string } {
  if (error instanceof Error) {
    return { message: error.message };
  }
  return { message: "Unexpected error" };
}

export function createAppServer(options?: {
  tutorialReactionTimeoutMs?: number;
  multiplayerReactionTimeoutMs?: number;
  botDelayMs?: number;
